    17→
    18→RpcClientImpl::RpcClientImpl(const RpcClientOptions& options)
    19→    : _options(options)
    20→    , _is_running(false)
    21→    , _next_request_id(0)
    22→    , _epoch_time(ptime_now())
    23→    , _ticks_per_second(time_duration_seconds(1).ticks())
    24→    , _last_maintain_ticks(0)
    25→    , _last_print_connection_ticks(0)
    26→    , _live_stream_count(0)
    27→{
    28→    _slice_count = std::max(1, 1000 / MAINTAIN_INTERVAL_IN_MS);
    29→    _slice_quota_in = _options.max_throughput_in == -1 ?
    30→        -1 : std::max(0L, _options.max_throughput_in * 1024L * 1024L) / _slice_count;
    31→    _slice_quota_out = _options.max_throughput_out == -1 ?
    32→        -1 : std::max(0L, _options.max_throughput_out * 1024L * 1024L) / _slice_count;
    33→    _max_pending_buffer_size =
    34→        std::max(0L, _options.max_pending_buffer_size * 1024L * 1024L);
    35→    _keep_alive_ticks = _options.keep_alive_time == -1 ?
    36→        -1 : std::max(1, _options.keep_alive_time) * _ticks_per_second;
    37→    _print_connection_interval_ticks = _ticks_per_second * 60;
    38→
    39→#if defined( LOG )
    40→    LOG(INFO) << "RpcClientImpl(): quota_in="
    41→              << (_slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L))
    42→              << "MB/s, quota_out="
    43→              << (_slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L))
    44→              << "MB/s, max_pending_buffer_size="
    45→              << (_max_pending_buffer_size / (1024L * 1024L))
    46→              << "MB, keep_alive_time="
    47→              << (_keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second)
    48→              << "seconds";
    49→#else
    50→    SLOG(INFO, "RpcClientImpl(): quota_in=%lldMB/s, quota_out=%lldMB/s"
    51→            ", max_pending_buffer_size=%lldMB, keep_alive_time=%lldseconds",
    52→            _slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L),
    53→            _slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L),
    54→            _max_pending_buffer_size / (1024L * 1024L),
    55→            _keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second);
    56→#endif
    57→}
    58→
    59→RpcClientImpl::~RpcClientImpl()
    60→{
    61→    SOFA_PBRPC_FUNCTION_TRACE;
    62→    Stop();
    63→}
    64→
    65→void RpcClientImpl::Start()
    66→{
    67→    ScopedLocker<MutexLock> _(_start_stop_lock);
    68→    if (_is_running) return;
    69→
    70→    _flow_controller.reset(new FlowController(
    71→                _slice_quota_in == -1, _slice_quota_in,
    72→                _slice_quota_out == -1, _slice_quota_out));
    73→
    74→    _maintain_thread_group.reset(new ThreadGroupImpl(
    75→                2, "sofa_pbrpc_client_maintain_thread_group"));
    76→    _maintain_thread_group->start();
    77→
    78→    _callback_thread_group.reset(new ThreadGroupImpl(
    79→                _options.callback_thread_num, "sofa_pbrpc_client_callback_thread_group"));
    80→    _callback_thread_group->start();
    81→
    82→    _work_thread_group.reset(new ThreadGroupImpl(
    83→                _options.work_thread_num, "sofa_pbrpc_client_work_thread_group"));
    84→    _work_thread_group->start();
    85→
    86→    _timer_worker.reset(new TimerWorker(_maintain_thread_group->io_service()));
    87→    _timer_worker->set_time_duration(time_duration_milliseconds(MAINTAIN_INTERVAL_IN_MS)); 
    88→    _timer_worker->set_work_routine(boost::bind(
    89→                &RpcClientImpl::TimerMaintain, shared_from_this(), _1));
    90→    _timer_worker->start();
    91→
    92→    _timeout_manager.reset(new RpcTimeoutManager(_maintain_thread_group->io_service()));
    93→    _timeout_manager->start();
    94→
    95→    _is_running = true;
    96→
    97→#if defined( LOG )
    98→    LOG(INFO) << "Start(): rpc client started";
    99→#else
   100→    SLOG(INFO, "Start(): rpc client started");
   101→#endif
   102→}
   103→
   104→void RpcClientImpl::Stop()
   105→{
   106→    ScopedLocker<MutexLock> _(_start_stop_lock);
   107→    if (!_is_running) return;
   108→    _is_running = false;
   109→
   110→    _timeout_manager->stop();
   111→    _timer_worker->stop();
   112→    StopStreams();
   113→    _work_thread_group->stop();
   114→
   115→    _timeout_manager.reset();
   116→    _timer_worker.reset();
   117→    ClearStreams();
   118→    _callback_thread_group->stop();
   119→    _maintain_thread_group->stop();
   120→
   121→    _work_thread_group.reset();
   122→    _callback_thread_group.reset();
   123→    _maintain_thread_group.reset();
   124→    _flow_controller.reset();
   125→
   126→#if defined( LOG )
   127→    LOG(INFO) << "Stop(): rpc client stopped";
   128→#else
   129→    SLOG(INFO, "Stop(): rpc client stopped");
   130→#endif
   131→}
