   202→int RpcClientImpl::ConnectionCount()
   203→{
   204→    return _live_stream_count;
   205→}
   206→
   207→// Rpc call method to remote endpoint.
   208→//
   209→// The call can be done in following cases:
   210→// * send failed
   211→// * timeouted
   212→// * received response
   213→void RpcClientImpl::CallMethod(const google::protobuf::Message* request,
   214→        google::protobuf::Message* response,
   215→        const RpcControllerImplPtr& cntl)
   216→{
   217→    if (!_is_running)
   218→    {
   219→#if defined( LOG )
   220→        LOG(ERROR) << "CallMethod(): client not in running, ignore";
   221→#else
   222→        SLOG(ERROR, "CallMethod(): client not in running, ignore");
   223→#endif
   224→        cntl->Done(RPC_ERROR_NOT_IN_RUNNING, "client not in running, should start it first");
   225→        return;
   226→    }
   227→
   228→    // get the stream
   229→    RpcClientStreamPtr stream = FindOrCreateStream(cntl->RemoteEndpoint());
   230→    if (!stream)
   231→    {
   232→#if defined( LOG )
   233→        LOG(ERROR) << "CallMethod(): create socket stream failed: "
   234→                   << RpcEndpointToString(cntl->RemoteEndpoint());
   235→#else
   236→        SLOG(ERROR, "CallMethod(): create socket stream failed: %s",
   237→                RpcEndpointToString(cntl->RemoteEndpoint()).c_str());
   238→#endif
   239→        cntl->Done(RPC_ERROR_CREATE_STREAM, "create stream failed, maybe exceed connection limit");
   240→        return;
   241→    }
   242→    cntl->SetRpcClientStream(stream);
   243→
   244→    // check the pending buffer full
   245→    if (stream->pending_buffer_size() > stream->max_pending_buffer_size())
   246→    {
   247→#if defined( LOG )
   248→#else
   249→        SLOG(DEBUG, "CallMethod(): pending buffer full: %s",
   250→                RpcEndpointToString(cntl->RemoteEndpoint()).c_str());
   251→#endif
   252→        cntl->Done(RPC_ERROR_SEND_BUFFER_FULL, "pending buffer full");
   253→        return;
   254→    }
   255→
   256→    // generate sequence id
   257→    cntl->SetSequenceId(GenerateSequenceId());
   258→
   259→    // prepare request buffer
   260→    RpcMeta meta;
   261→    meta.set_type(RpcMeta::REQUEST);
   262→    meta.set_sequence_id(cntl->SequenceId());
   263→    meta.set_method(cntl->MethodId());
   264→    meta.set_compress_type(cntl->RequestCompressType());
   265→    meta.set_expected_response_compress_type(cntl->ResponseCompressType());
   266→
   267→    RpcMessageHeader header;
   268→    int header_size = sizeof(header);
   269→    WriteBuffer write_buffer;
   270→    int64 header_pos = write_buffer.Reserve(header_size);
   271→    if (header_pos < 0)
   272→    {
   273→#if defined( LOG )
   274→        LOG(ERROR) << "CallMethod(): " << RpcEndpointToString(cntl->RemoteEndpoint())
   275→                   << ": reserve rpc message header failed";
   276→#else
   277→        SLOG(ERROR, "CallMethod(): %s: reserve rpc message header failed",
   278→                RpcEndpointToString(cntl->RemoteEndpoint()).c_str());
   279→#endif
   280→        cntl->Done(RPC_ERROR_SERIALIZE_REQUEST, "reserve rpc message header failed");
   281→        return;
   282→    }
   283→    if (!meta.SerializeToZeroCopyStream(&write_buffer))
   284→    {
   285→#if defined( LOG )
   286→        LOG(ERROR) << "CallMethod(): " << RpcEndpointToString(cntl->RemoteEndpoint())
   287→                   << ": serialize rpc meta failed";
   288→#else
   289→        SLOG(ERROR, "CallMethod(): %s: serialize rpc meta failed",
   290→                RpcEndpointToString(cntl->RemoteEndpoint()).c_str());
   291→#endif
   292→        cntl->Done(RPC_ERROR_SERIALIZE_REQUEST, "serialize rpc meta failed");
   293→        return;
   294→    }
   295→    header.meta_size = static_cast<int>(write_buffer.ByteCount() - header_pos - header_size);
   296→    bool serialize_request_return = false;
   297→    if (meta.compress_type() == CompressTypeNone)
   298→    {
   299→        serialize_request_return = request->SerializeToZeroCopyStream(&write_buffer);
   300→    }
   301→    else
   302→    {
   303→        ::sofa::pbrpc::scoped_ptr<AbstractCompressedOutputStream> os(
   304→                get_compressed_output_stream(&write_buffer, meta.compress_type()));
   305→        serialize_request_return = request->SerializeToZeroCopyStream(os.get());
   306→        os->Flush();
   307→    }
   308→    if (!serialize_request_return)
   309→    {
   310→#if defined( LOG )
   311→        LOG(ERROR) << "CallMethod(): " << RpcEndpointToString(cntl->RemoteEndpoint())
   312→                   << ": serialize request message failed";
   313→#else
   314→        SLOG(ERROR, "CallMethod(): %s: serialize request message failed",
   315→                RpcEndpointToString(cntl->RemoteEndpoint()).c_str());
   316→#endif
   317→        cntl->Done(RPC_ERROR_SERIALIZE_REQUEST, "serialize request message failed");
   318→        return;
   319→    }
   320→    header.data_size = write_buffer.ByteCount() - header_pos - header_size - header.meta_size;
   321→    header.message_size = header.meta_size + header.data_size;
   322→    write_buffer.SetData(header_pos, reinterpret_cast<const char*>(&header), header_size);
   323→
   324→    ReadBufferPtr read_buffer(new ReadBuffer());
   325→    write_buffer.SwapOut(read_buffer.get());
   326→    cntl->SetRequestBuffer(read_buffer);
   327→
   328→    // push callback
   329→    cntl->PushDoneCallback(boost::bind(&RpcClientImpl::DoneCallback, shared_from_this(), response, _1));
   330→
   331→    // add to timeout manager if need
   332→    int64 timeout = cntl->Timeout();
   333→    if (timeout > 0)
   334→    {
   335→        if (!_timeout_manager->add(cntl))
   336→        {
   337→#if defined( LOG )
   338→            LOG(ERROR) << "CallMethod(): " << RpcEndpointToString(cntl->RemoteEndpoint())
   339→                       << ": add to timeout manager failed: timeout=" << timeout << "ms";
   340→#else
   341→            SLOG(ERROR, "CallMethod(): %s: add to timeout manager failed: timeout=%llsms",
   342→                    RpcEndpointToString(cntl->RemoteEndpoint()).c_str(), timeout);
   343→#endif
   344→            cntl->Done(RPC_ERROR_REQUEST_TIMEOUT, "add to timeout manager failed, maybe too short timeout");
   345→            return;
   346→        }
   347→    }
   348→
   349→    // call method
   350→    stream->call_method(cntl);
   351→}
   352→
   353→const ThreadGroupImplPtr& RpcClientImpl::GetCallbackThreadGroup() const
   354→{
   355→    return _callback_thread_group;
   356→}
   357→
   358→bool RpcClientImpl::ResolveAddress(const std::string& address,
   359→        RpcEndpoint* endpoint)
   360→{
   361→    return sofa::pbrpc::ResolveAddress(_work_thread_group->io_service(), address, endpoint);
   362→}
   363→
   364→RpcClientStreamPtr RpcClientImpl::FindOrCreateStream(
   365→        const RpcEndpoint& remote_endpoint)
   366→{
   367→    RpcClientStreamPtr stream;
   368→    bool create = false;
   369→    {
   370→        ScopedLocker<FastLock> _(_stream_map_lock);
   371→        StreamMap::iterator find = _stream_map.find(remote_endpoint);
   372→        if (find != _stream_map.end() && !find->second->is_closed())
   373→        {
   374→            stream = find->second;
   375→        }
   376→        else
   377→        {
   378→            stream.reset(new RpcClientStream(_work_thread_group->io_service(), remote_endpoint));
   379→            stream->set_flow_controller(_flow_controller);
   380→            stream->set_max_pending_buffer_size(_max_pending_buffer_size);
   381→            stream->reset_ticks((ptime_now() - _epoch_time).ticks(), true);
   382→
   383→            _stream_map[remote_endpoint] = stream;
   384→            create = true;
   385→        }
   386→    }
   387→    if (create)
   388→    {
   389→        stream->async_connect();
   390→    }
   391→    return stream;
   392→}
   393→
   394→void RpcClientImpl::StopStreams()
   395→{
   396→    ScopedLocker<FastLock> _(_stream_map_lock);
   397→    for (StreamMap::iterator it = _stream_map.begin();
   398→            it != _stream_map.end(); ++it)
   399→    {
   400→        it->second->close("client stopped");
   401→    }
   402→}
   403→
   404→void RpcClientImpl::ClearStreams()
   405→{
   406→    ScopedLocker<FastLock> _(_stream_map_lock);
   407→    _stream_map.clear();
   408→}
   409→
   410→void RpcClientImpl::DoneCallback(google::protobuf::Message* response,
   411→        const RpcControllerImplPtr& cntl)
   412→{
   413→    // erase from RpcTimeoutManager
   414→    _timeout_manager->erase(cntl->TimeoutId());
   415→
   416→    // deserialize response
   417→    if (!cntl->Failed())
   418→    {
   419→        SCHECK(response != NULL);
   420→        SCHECK(cntl->ResponseBuffer());
   421→        ReadBufferPtr buffer = cntl->ResponseBuffer();
   422→        CompressType compress_type = cntl->ResponseCompressType();
   423→        bool parse_response_return = false;
   424→        if (compress_type == CompressTypeNone)
   425→        {
   426→            parse_response_return = response->ParseFromZeroCopyStream(buffer.get());
   427→        }
   428→        else
   429→        {
   430→            ::sofa::pbrpc::scoped_ptr<AbstractCompressedInputStream> is(
   431→                    get_compressed_input_stream(buffer.get(), compress_type));
   432→            parse_response_return = response->ParseFromZeroCopyStream(is.get());
   433→        }
   434→        if (!parse_response_return)
   435→        {
   436→#if defined( LOG )
   437→            LOG(ERROR) << "DoneCallback(): " << RpcEndpointToString(cntl->RemoteEndpoint())
   438→                       << ": parse response message pb failed";
   439→#else
   440→            SLOG(ERROR, "DoneCallback(): %s: parse response message pb failed",
   441→                    RpcEndpointToString(cntl->RemoteEndpoint()).c_str());
   442→#endif
   443→            cntl->SetFailed(RPC_ERROR_PARSE_RESPONSE_MESSAGE, "parse response message pb failed");
   444→        }
   445→    }
   446→}
   447→
   448→void RpcClientImpl::TimerMaintain(const PTime& now)
   449→{
   450→    SOFA_PBRPC_FUNCTION_TRACE;
   451→
   452→    int64 now_ticks = (now - _epoch_time).ticks();
   453→
   454→    std::list<RpcClientStreamPtr> live_streams;
   455→    std::list<RpcClientStreamPtr> closed_streams;
   456→    int live_count = 0;
   457→    {
   458→        ScopedLocker<FastLock> _(_stream_map_lock);
   459→        for (StreamMap::iterator it = _stream_map.begin(); it != _stream_map.end(); )
   460→        {
   461→            const RpcClientStreamPtr& stream = it->second;
   462→
   463→            if (_keep_alive_ticks != -1
   464→                    && now_ticks - stream->last_rw_ticks() >= _keep_alive_ticks)
   465→            {
   466→                stream->close("keep alive timeout");
   467→            }
   468→
   469→            if (stream->is_closed())
   470→            {
   471→                closed_streams.push_back(stream);
   472→                _stream_map.erase(it++);
   473→            }
   474→            else
   475→            {
   476→                stream->reset_ticks(now_ticks, false);
   477→                live_streams.push_back(stream);
   478→                ++live_count;
   479→                ++it;
   480→            }
   481→        }
   482→    }
   483→    _live_stream_count = live_count;
   484→
   485→    // flow control
   486→    if (_slice_quota_in != -1)
   487→    {
   488→        // reset quota pool
   489→        _flow_controller->reset_read_quota(_slice_quota_in);
   490→
   491→        // collect streams need to trigger
   492→        std::vector<FlowControlItem> trigger_list;
   493→        for (std::list<RpcClientStreamPtr>::iterator it = live_streams.begin();
   494→                it != live_streams.end(); ++it)
   495→        {
   496→            int token = (*it)->read_quota_token();
   497→            if (token <= 0)
   498→            {
   499→                // only need trigger streams whose token <= 0
   500→                trigger_list.push_back(FlowControlItem(token, (*it).get()));
   501→            }
   502→        }
   503→
   504→        // sort by token: token closer to zero, earlier to trigger
   505→        std::sort(trigger_list.begin(), trigger_list.end());
   506→
   507→        // trigger in order
   508→        for (std::vector<FlowControlItem>::iterator t_it = trigger_list.begin();
   509→                t_it != trigger_list.end(); ++t_it)
   510→        {
   511→            t_it->stream->trigger_receive();
   512→        }
   513→    }
   514→    if (_slice_quota_out != -1)
   515→    {
   516→        // reset quota pool
   517→        _flow_controller->reset_write_quota(_slice_quota_out);
   518→
   519→        // collect streams need to trigger
   520→        std::vector<FlowControlItem> trigger_list;
   521→        for (std::list<RpcClientStreamPtr>::iterator it = live_streams.begin();
   522→                it != live_streams.end(); ++it)
   523→        {
   524→            int token = (*it)->write_quota_token();
   525→            if (token <= 0)
   526→            {
   527→                // only need trigger streams whose token <= 0
   528→                trigger_list.push_back(FlowControlItem(token, (*it).get()));
   529→            }
   530→        }
   531→
   532→        // sort by token: token closer to zero, earlier to trigger
   533→        std::sort(trigger_list.begin(), trigger_list.end());
   534→
   535→        // trigger in order
   536→        for (std::vector<FlowControlItem>::iterator t_it = trigger_list.begin();
   537→                t_it != trigger_list.end(); ++t_it)
   538→        {
   539→            t_it->stream->trigger_send();
   540→        }
   541→    }
   542→
   543→    if (now_ticks - _last_print_connection_ticks >= _print_connection_interval_ticks)
   544→    {
   545→        _last_print_connection_ticks = now_ticks;
   546→#if defined( LOG )
   547→        LOG(INFO) << "TimerMaintain(): countof(RpcListener)="
   548→                   << SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcListener)
   549→                   << ", countof(RpcByteStream)=" << SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcByteStream)
   550→                   << ", live_stream_count=" << _live_stream_count;
   551→#else
   552→        SLOG(INFO, "TimerMaintain(): countof(RpcListener)=%d"
   553→                ", countof(RpcByteStream)=%d, live_stream_count=%d",
   554→                SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcListener),
   555→                SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcByteStream),
   556→                _live_stream_count);
   557→#endif
   558→    }
   559→
   560→    _last_maintain_ticks = now_ticks;
   561→}
   562→
   563→uint64 RpcClientImpl::GenerateSequenceId()
   564→{
   565→    return static_cast<uint64>(++_next_request_id);
   566→}
   567→
   568→} // namespace pbrpc
   569→} // namespace sofa
