    46→    void start()
    47→    {
    48→        ScopedLocker<MutexLock> _(_start_stop_lock);
    49→        if (_is_running)
    50→            return;
    51→        _is_running = true;
    52→
    53→        _timer_worker.reset(new TimerWorker(_io_service));
    54→        _timer_worker->set_time_duration(time_duration_milliseconds(100));
    55→        _timer_worker->set_work_routine(boost::bind(
