    71→    }
    72→
    73→    // Add a timeout event.
    74→    // If "expiration" of the "cntl" is a special value or already timeout, return false.
    75→    // Else put the "cntl" into the manager, and return true.
    76→    bool add(const RpcControllerImplPtr& cntl)
    77→    {
    78→        const PTime& expiration = cntl->Expiration();
    79→        if (expiration.is_special() || expiration <= _epoch_time)
    80→        {
    81→            cntl->SetTimeoutId(0u);
    82→            return false;
    83→        }
    84→        int64 expiration_ticks = (expiration - _epoch_time).ticks();
    85→        {
    86→            ScopedLocker<FastLock> _(_add_list_lock);
    87→            uint64 timeout_id = _next_id++;
    88→            cntl->SetTimeoutId(timeout_id);
