   124→        // process add list and erase list
   125→        EventList tmp_add_list;
   126→        {
   127→            ScopedLocker<FastLock> _(_add_list_lock);
   128→            tmp_add_list.swap(_add_list);
   129→        }
   130→        IdSet tmp_erase_set;
   131→        {
   132→            ScopedLocker<FastLock> _(_erase_set_lock);
   133→            tmp_erase_set.swap(_erase_set);
   134→        }
   135→
   136→        ScopedLocker<FastLock> _(_events_lock);
   137→        EventList::iterator add_it = tmp_add_list.begin();
   138→        IdSet::iterator erase_it = tmp_erase_set.begin();
   139→        while (add_it != tmp_add_list.end() && erase_it != tmp_erase_set.end())
   140→        {
   141→            if (add_it->id < *erase_it)
   142→            {
   143→                if (add_it->expiration <= now_ticks)
   144→                {
   145→                    // expired, notify
   146→                    notify_timeout(add_it->cntl);
   147→                }
   148→                else
   149→                {
   150→                    // add into EventSet
   151→                    _events.insert(*add_it);
   152→                }
   153→                ++add_it;
   154→            }
   155→            else if (add_it->id > *erase_it)
   156→            {
   157→                // erase from EventSet
   158→                _events.get<INDEX_BY_ID>().erase(*erase_it);
   159→                ++erase_it;
   160→            }
   161→            else // add_it->id == *erase_it
   162→            {
   163→                // ignore it
   164→                ++add_it;
   165→                ++erase_it;
   166→            }
   167→        }
   168→        while (add_it != tmp_add_list.end())
   169→        {
   170→            if (add_it->expiration <= now_ticks)
   171→            {
   172→                // expired, notify
   173→                notify_timeout(add_it->cntl);
   174→            }
   175→            else
   176→            {
   177→                // add into EventSet
   178→                _events.insert(*add_it); // add into EventSet
   179→            }
   180→            ++add_it;
   181→        }
   182→        while (erase_it != tmp_erase_set.end())
   183→        {
   184→            // erase from EventSet
   185→            _events.get<INDEX_BY_ID>().erase(*erase_it);
   186→            ++erase_it;
   187→        }
   188→
   189→        // process EventSet
   190→        ExpirationIndex& exp_index = _events.get<INDEX_BY_EXPIRATION>();
   191→        ExpirationIndex::iterator exp_end = exp_index.upper_bound(now_ticks);
   192→        for (ExpirationIndex::iterator exp_it = exp_index.begin();
   193→                exp_it != exp_end; ++exp_it)
   194→        {
