   211→private:
   212→    struct Event
   213→    {
   214→        uint64 id; // 0 means invalid id
   215→        int64 expiration;
   216→        RpcControllerImplWPtr cntl;
   217→        Event(uint64 i, int64 e, const RpcControllerImplWPtr& c)
   218→            : id(i), expiration(e), cntl(c) {}
   219→        Event(const Event& o)
   220→            : id(o.id), expiration(o.expiration), cntl(o.cntl) {}
   221→        Event& operator=(const Event& o) {
   222→            if (this != &o) {
   223→                id = o.id;
   224→                expiration = o.expiration;
   225→                cntl = o.cntl;
   226→            }
   227→            return *this;
   228→        }
   229→        void swap(Event& o) {
   230→            std::swap(id, o.id);
   231→            std::swap(expiration, o.expiration);
   232→            cntl.swap(o.cntl);
   233→        }
   234→    };
   235→
   236→    typedef boost::multi_index_container<
   237→        Event,
   238→        boost::multi_index::indexed_by<
   239→            boost::multi_index::ordered_unique< boost::multi_index::member<
   240→            Event, uint64, &Event::id
   241→            > >,
   242→        boost::multi_index::ordered_non_unique< boost::multi_index::member<
   243→            Event, int64, &Event::expiration
   244→            > >
   245→        >
   246→    > EventSet;
   247→
   248→    enum {
   249→        INDEX_BY_ID = 0,
   250→        INDEX_BY_EXPIRATION = 1,
   251→    };
   252→        
   253→    typedef EventSet::nth_index<INDEX_BY_EXPIRATION>::type ExpirationIndex;
   254→    typedef EventSet::nth_index<INDEX_BY_ID>::type IdIndex;
   255→    typedef std::deque<Event> EventList;
   256→    typedef std::set<uint64> IdSet;
   257→
   258→    IOService& _io_service;
   259→    volatile bool _is_running;
   260→    MutexLock _start_stop_lock;
   261→    PTime _epoch_time;
   262→
   263→    uint64 _next_id;
   264→    EventSet _events;
   265→    FastLock _events_lock;
   266→
   267→    EventList _add_list; // must be in order of id
   268→    FastLock _add_list_lock;
   269→    IdSet _erase_set; // in order of id
   270→    FastLock _erase_set_lock;
   271→
   272→    TimerWorkerPtr _timer_worker;
   273→
   274→    SOFA_PBRPC_DISALLOW_EVIL_CONSTRUCTORS(RpcTimeoutManager);
   275→}; // class RpcTimeoutManager
